import React from "react";
import OTPInput from "./OTPInput";

const s = {
  info: { fontSize: "13px", color: "var(--text-muted)", marginBottom: "16px", lineHeight: 1.6 },
  bold: { color: "var(--text-primary)", fontWeight: 600 },
  label: { display: "block", fontSize: "12px", fontWeight: 600, color: "#444", marginBottom: "5px", letterSpacing: ".3px" },
  resendRow: { fontSize: "12px", color: "var(--text-muted)", marginBottom: "20px", marginTop: "10px" },
  resendBtn: { color: "var(--brand)", background: "none", border: "none", fontSize: "12px", cursor: "pointer", padding: 0 },
  timer: { color: "var(--error)" },
  btnBack: {
    flex: "0 0 90px", padding: "13px", background: "#888",
    border: "none", borderRadius: "var(--radius-sm)", color: "#fff",
    fontSize: "14px", fontWeight: 600, cursor: "pointer", minHeight: "48px",
  },
  btnVerify: {
    flex: 1, padding: "13px", background: "var(--accent)",
    border: "none", borderRadius: "var(--radius-sm)", color: "#fff",
    fontSize: "15px", fontWeight: 700, cursor: "pointer",
    boxShadow: "var(--shadow-btn)", transition: "background .15s", minHeight: "48px",
  },
  btnDisabled: { background: "#f5a77a", cursor: "not-allowed" },
  hint: {
    fontSize: "11px", color: "var(--text-muted)", marginTop: "12px",
    background: "#f9f9f9", border: "1px solid var(--border)",
    borderRadius: "var(--radius-sm)", padding: "8px 10px", lineHeight: 1.6,
  },
  errMsg: { fontSize: "11px", color: "var(--error)", marginTop: "6px" },
};

export default function Step3OTP({ mobile, countryCode, otpValue, onOtpChange, timerSeconds, timerActive, onVerify, onResend, onBack, loading, error }) {
  return (
    <div className="fade-slide-in">
      <p style={s.info}>
        We've sent a 6-digit OTP to{" "}
        <span style={s.bold}>{countryCode} {mobile}</span>.
        Enter it below to verify your account.
      </p>

      <label style={s.label}>Enter OTP</label>
      <OTPInput value={otpValue} onChange={onOtpChange} hasError={!!error} length={6} />
      {error && <p style={s.errMsg}>{error}</p>}

      <div style={s.resendRow}>
        Didn't receive it?{" "}
        <button style={{ ...s.resendBtn, ...(timerActive ? { color: "var(--text-muted)", cursor: "not-allowed" } : {}) }}
          onClick={timerActive ? undefined : onResend} disabled={timerActive}>
          Resend OTP
        </button>
        {timerActive && <span style={s.timer}> ({timerSeconds}s)</span>}
      </div>

      {/* btn-row-2col stacks on mobile */}
      <div className="btn-row-2col">
        <button style={s.btnBack} onClick={onBack} disabled={loading}>← Back</button>
        <button style={{ ...s.btnVerify, ...(loading ? s.btnDisabled : {}) }}
          onClick={onVerify} disabled={loading}
          onMouseEnter={(e) => { if (!loading) e.target.style.background = "var(--accent-dark)"; }}
          onMouseLeave={(e) => { if (!loading) e.target.style.background = "var(--accent)"; }}>
          {loading ? "Verifying…" : "Verify & Register"}
        </button>
      </div>

      <div style={s.hint}>
        💡 <strong>Demo mode:</strong> Check browser console for OTP, or enter <code>000000</code> to bypass.
      </div>
    </div>
  );
}
